export type GoogleSansFlexSubset =
  | "canadian-aboriginal"
  | "cherokee"
  | "latin"
  | "latin-ext"
  | "math"
  | "nushu"
  | "symbols"
  | "syriac"
  | "tifinagh"
  | "vietnamese";
export type GoogleSansFlexOptions = GoogleFontOptions<
  GoogleSansFlexWeight,
  GoogleSansFlexStyle,
  GoogleSansFlexSubset
>;

/**
 * Google Sans Flex — Google font. Pass `weights`/`styles` to register a subset of
 * faces (omit for all) and `subset` to choose the character set (default "latin").
 */
export default class GoogleSansFlex extends GoogleFont<
  GoogleSansFlexWeight,
  GoogleSansFlexStyle,
  GoogleSansFlexSubset
> {
  constructor(options?: GoogleSansFlexOptions) {
    super(FAMILY, FACES, options);
  }
}
